SELECT * FROM mate_approval_grant WHERE workspace_id = #{workspaceId} AND revoked = 0 AND deleted = 0 AND (expire_at IS NULL OR expire_at > CURRENT_TIMESTAMP) AND CASE max_severity WHEN 'HIGH' THEN 3 WHEN 'MEDIUM' THEN 2 WHEN 'LOW' THEN 1 ELSE 0 END >= CASE #{evalSeverity} WHEN 'HIGH' THEN 3 WHEN 'MEDIUM' THEN 2 WHEN 'LOW' THEN 1 ELSE 0 END AND (tool_name IS NULL OR tool_name = #{toolName}) AND ( rule_id IS NULL
OR rule_id IN
#{rid}
) AND ( (scope_type = 'CONVERSATION' AND scope_id = #{conversationId}) OR (scope_type = 'AGENT' AND scope_id = #{agentId}) OR (scope_type = 'USER' AND scope_id = #{userId}) OR (scope_type = 'WORKSPACE' AND scope_id = #{workspaceScopeId}) ) ORDER BY CASE scope_type WHEN 'CONVERSATION' THEN 1 WHEN 'AGENT' THEN 2 WHEN 'USER' THEN 3 WHEN 'WORKSPACE' THEN 4 END, CASE WHEN rule_id IS NOT NULL THEN 0 ELSE 1 END, CASE WHEN tool_name IS NOT NULL THEN 0 ELSE 1 END LIMIT 1
